:root {
  /* Color system (from design) */
  --color-primary-900: #0F172A; /* dark navy title bands */
  --color-primary-800: #1F2933; /* dark header/nav text */

  --color-accent-gold: #F59E0B;
  --color-accent-red: #EF4444;
  --color-accent-blue: #2563EB;

  --color-bg-page: #F5F5F5; /* light gray page background */
  --color-bg-card: #FFFFFF;

  --color-border-subtle: #E5E7EB;

  --color-text-main: #111827;
  --color-text-muted: #6B7280;

  --shadow-soft: 0 6px 20px rgba(15, 23, 42, 0.08);

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --fs-h1: 32px;
  --fs-h2: 24px;
  --fs-h3: 20px;
  --fs-body: 16px;
  --fs-small: 14px;

  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;
  --fw-semibold: 600;
  --fw-bold: 700;

  --lh-tight: 1.2;
  --lh-normal: 1.5;
  --lh-relaxed: 1.7;

  /* Spacing scale (8px base) */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radius */
  --radius-sm: 4px;
  --radius-md: 6px;
  --radius-pill: 999px;

  /* Layout */
  --max-width-page: 1160px;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body.site {
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--fs-body);
  line-height: var(--lh-relaxed);
  color: var(--color-text-main);
  background-color: var(--color-bg-page);
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: var(--color-accent-blue);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.container {
  max-width: var(--max-width-page);
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Header */

.site-header {
  background-color: #FFFFFF;
  border-bottom: 1px solid var(--color-border-subtle);
}

.header-top {
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
}

.site-logo {
  font-family: var(--font-heading);
  font-weight: var(--fw-bold);
  font-size: 26px;
  color: #000000;
  text-decoration: none;
  white-space: nowrap;
}

/* Search */

.site-search {
  flex: 1 1 auto;
  max-width: 360px;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

.search-field {
  position: relative;
}

.search-field input[type="search"] {
  width: 100%;
  padding: 8px 40px 8px 12px;
  font-family: var(--font-body);
  font-size: 15px;
  border-radius: var(--radius-pill);
  border: 1px solid var(--color-border-subtle);
  background-color: #FFFFFF;
  outline: none;
  transition: border-color 0.15s ease, box-shadow 0.15s ease;
}

.search-field input[type="search"]::placeholder {
  color: var(--color-text-muted);
}

.search-field input[type="search"]:focus {
  border-color: var(--color-accent-blue);
  box-shadow: 0 0 0 1px rgba(37, 99, 235, 0.3);
}

.search-button {
  position: absolute;
  right: 6px;
  top: 50%;
  transform: translateY(-50%);
  width: 26px;
  height: 26px;
  border-radius: 50%;
  border: none;
  padding: 0;
  background-color: var(--color-accent-blue);
  cursor: pointer;
}

/* Pure-CSS magnifier icon */
.search-button::before {
  content: "";
  position: absolute;
  inset: 7px;
  border-radius: 50%;
  border: 2px solid #FFFFFF;
}

.search-button::after {
  content: "";
  position: absolute;
  width: 8px;
  height: 2px;
  border-radius: var(--radius-pill);
  background-color: #FFFFFF;
  transform: rotate(45deg);
  right: 4px;
  bottom: 6px;
}

/* Primary navigation */

.primary-nav {
  flex: 0 0 auto;
}

.primary-nav ul {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin: 0;
  padding: 0;
  list-style: none;
}

.primary-nav a {
  font-family: var(--font-body);
  font-size: 15px;
  font-weight: var(--fw-medium);
  color: var(--color-text-main);
  text-decoration: none;
  padding: 4px 0;
}

.primary-nav a:hover,
.primary-nav a:focus {
  color: var(--color-accent-blue);
}

.header-divider {
  border-top: 1px solid var(--color-border-subtle);
}

/* Breadcrumbs */

.breadcrumb-nav {
  background-color: #FFFFFF;
}

.breadcrumb-nav .container {
  padding-top: var(--space-2);
  padding-bottom: var(--space-2);
}

.breadcrumb {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  font-size: var(--fs-small);
}

.breadcrumb-item + .breadcrumb-item::before {
  content: "\00BB"; /* » */
  margin: 0 var(--space-1);
  color: var(--color-text-muted);
}

.breadcrumb-item a {
  color: var(--color-accent-blue);
}

.breadcrumb-current {
  font-weight: var(--fw-semibold);
  color: var(--color-text-main);
}

/* Main layout */

.site-main {
  padding-top: var(--space-5);
  padding-bottom: var(--space-6);
}

.layout-two-column {
  display: flex;
  align-items: flex-start;
  gap: var(--space-5);
}

.primary-column {
  flex: 0 0 66%;
}

.sidebar {
  flex: 0 0 34%;
}

/* Card patterns */

.content-card {
  background-color: var(--color-bg-card);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-soft);
  padding: var(--space-4);
}

.sidebar-card {
  background-color: var(--color-bg-card);
  border-radius: var(--radius-sm);
  box-shadow: var(--shadow-soft);
  padding: var(--space-4);
}

.sidebar-card + .sidebar-card {
  margin-top: var(--space-4);
}

.sidebar-card-title {
  margin: 0 0 var(--space-3);
  font-family: var(--font-heading);
  font-size: var(--fs-h2);
  line-height: var(--lh-tight);
}

/* Title bands (for article headers) */

.title-band {
  position: relative;
  background-color: var(--color-primary-900);
  color: #FFFFFF;
  padding: var(--space-4) var(--space-5);
  border-radius: var(--radius-sm);
  text-align: center;
  font-family: var(--font-heading);
  font-weight: var(--fw-bold);
  font-size: var(--fs-h1);
  line-height: var(--lh-tight);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  overflow: hidden;
}

.title-band::before,
.title-band::after {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  width: 6px;
}

.title-band::before {
  left: 0;
  background-color: var(--color-accent-gold);
}

.title-band::after {
  right: 0;
  background-color: var(--color-accent-gold);
}

.title-band--secondary {
  position: relative;
  background-color: var(--color-primary-900);
  color: #FFFFFF;
  padding: var(--space-3) var(--space-4);
  border-radius: var(--radius-sm);
  font-family: var(--font-heading);
  font-weight: var(--fw-semibold);
  font-size: var(--fs-h2);
  line-height: var(--lh-tight);
}

.title-band--secondary::before {
  content: "";
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 6px;
  background-color: var(--color-accent-red);
}

/* Footer */

.site-footer {
  background-color: #FFFFFF;
  border-top: 1px solid var(--color-border-subtle);
  margin-top: auto;
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: var(--space-4);
  padding-top: var(--space-5);
  padding-bottom: var(--space-4);
}

.footer-branding {
  flex: 1 1 260px;
}

.footer-logo {
  font-family: var(--font-heading);
  font-weight: var(--fw-bold);
  font-size: 22px;
  margin-bottom: var(--space-2);
  color: #000000;
}

.footer-description {
  margin: 0;
  font-size: var(--fs-small);
  color: var(--color-text-muted);
}

.footer-nav {
  flex: 2 1 340px;
}

.footer-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-3) var(--space-4);
}

.footer-links a {
  font-size: var(--fs-small);
  color: var(--color-text-main);
}

.footer-links a:hover,
.footer-links a:focus {
  color: var(--color-accent-blue);
}

.footer-bottom {
  border-top: 1px solid var(--color-border-subtle);
  background-color: #FFFFFF;
}

.footer-bottom-inner {
  padding-top: var(--space-2);
  padding-bottom: var(--space-3);
}

.footer-copy {
  margin: 0;
  font-size: 13px;
  color: var(--color-text-muted);
  text-align: center;
}

/* Utility typography */

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  font-weight: var(--fw-semibold);
  line-height: var(--lh-tight);
  margin-top: 0;
}

p {
  margin-top: 0;
  margin-bottom: var(--space-3);
}

code,
pre {
  font-family: var(--font-code);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    flex-wrap: wrap;
    align-items: flex-start;
  }

  .site-search {
    order: 3;
    width: 100%;
    max-width: none;
  }

  .primary-nav {
    order: 2;
    width: 100%;
  }

  .primary-nav ul {
    flex-wrap: wrap;
    justify-content: flex-end;
    gap: var(--space-2) var(--space-3);
  }

  .layout-two-column {
    flex-direction: column;
  }

  .primary-column,
  .sidebar {
    flex-basis: 100%;
  }
}

@media (max-width: 600px) {
  .container {
    padding-left: var(--space-3);
    padding-right: var(--space-3);
  }

  .header-top {
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .site-logo {
    font-size: 20px;
  }

  .breadcrumb-nav .container {
    padding-top: var(--space-1);
    padding-bottom: var(--space-1);
  }

  .title-band {
    padding: var(--space-3) var(--space-3);
    font-size: 24px;
  }

  .title-band--secondary {
    font-size: 18px;
  }
}
